  1→import express from "express";
  2→import cors from 'cors';
  3→import compression from "compression";
  4→import helmet from "helmet";
  5→import net from "node:net";
  6→import sharp from "sharp";
  7→import router from "./routes/routes.js";
  8→import sitemapRouter from "./routes/sitemapRoutes.js";
  9→import supabase from "./services/supabase.js";
 10→import { SITE_URL as SITE_URL_SHARED, makePostUrl as makePostUrlShared } from "./utils/urlUtils.js";
 11→
 12→const app = express();
 13→const PORT = process.env.PORT || 3000;
 14→const SITE_URL = SITE_URL_SHARED;
 15→const DEFAULT_OG_IMAGE_URL = `${SITE_URL}/assets/no-image.png`;
 16→const DEFAULT_OG_IMAGE_WIDTH = 1200;
 17→const DEFAULT_OG_IMAGE_HEIGHT = 630;
 18→const SOCIAL_PREVIEW_MAX_CHARS = 160;
 19→const REMOTE_IMAGE_FETCH_TIMEOUT_MS = 7000;
 20→const REMOTE_IMAGE_MAX_BYTES = 15 * 1024 * 1024;
 21→const SHARE_IMAGE_FETCH_USER_AGENT = 'IskrybShareBot/1.0 (+https://iskrib.com)';
 22→const META_FB_APP_ID = (process.env.META_FB_APP_ID || process.env.FB_APP_ID || process.env.VITE_FB_APP_ID || '').trim();
 23→const SHARE_IMAGE_DEBUG = false;
 24→const SUPABASE_URL = (process.env.SUPABASE_URL || '').trim();
 25→
 26→const normalizeWhitespace = (value) => String(value ?? '')
 27→    .replace(/\s+/g, ' ')
 28→    .trim();
 29→
 30→const toPreviewText = (value, maxLength = SOCIAL_PREVIEW_MAX_CHARS) => {
 31→    const normalized = normalizeWhitespace(value);
 32→    if (!normalized) return '';
 33→    if (normalized.length <= maxLength) return normalized;
 34→    if (maxLength <= 3) return normalized.slice(0, maxLength);
 35→    return `${normalized.slice(0, maxLength - 3).trimEnd()}...`;
 36→};
 37→
 38→const escHtml = (str) => String(str)
 39→    .replace(/&/g, '&amp;')
 40→    .replace(/</g, '&lt;')
 41→    .replace(/>/g, '&gt;')
 42→    .replace(/"/g, '&quot;');
 43→
 44→const makePostUrl = makePostUrlShared;
 45→
 46→const getRequestOrigin = (req) => {
 47→    const forwardedProto = String(req.headers['x-forwarded-proto'] || '').split(',')[0].trim().toLowerCase();
 48→    const forwardedHost = String(req.headers['x-forwarded-host'] || '').split(',')[0].trim();
 49→    const host = forwardedHost || req.get('host') || '';
 50→    const requestProtocol = String(req.protocol || '').trim().toLowerCase();
 51→    const protocol = forwardedProto === 'http' || forwardedProto === 'https'
 52→        ? forwardedProto
 53→        : requestProtocol === 'http' || requestProtocol === 'https'
 54→            ? requestProtocol
 55→            : 'https';
 56→
 57→    if (!host) {
 58→        return SITE_URL;
 59→    }
 60→
 61→    return `${protocol}://${host}`;
 62→};
 63→
 64→const pickFirstNonEmptyString = (...values) => {
 65→    for (const value of values) {
 66→        if (typeof value === 'string') {
 67→            const trimmed = value.trim();
 68→            if (trimmed) return trimmed;
 69→        }
 70→    }
 71→    return '';
 72→};
 73→
 74→const parseImageDimension = (value) => {
 75→    const parsed = Number(value);
 76→    if (!Number.isFinite(parsed)) return undefined;
 77→    return parsed;
 78→};
 79→
 80→const imageFromNodeLike = (nodeLike) => {
 81→    if (!nodeLike || typeof nodeLike !== 'object') return null;
 82→
 83→    const src = pickFirstNonEmptyString(
 84→        nodeLike.src,
 85→        nodeLike.url,
 86→        nodeLike.image_url,
 87→        nodeLike.imageUrl,
 88→        nodeLike?.payload?.src,
 89→        nodeLike?.data?.src
 90→    );
 91→    if (!src) return null;
 92→
 93→    return {
 94→        src,
 95→        width: parseImageDimension(nodeLike.width),
 96→        height: parseImageDimension(nodeLike.height),
 97→    };
 98→};
 99→
100→const extractFromLexical = (contentJson) => {
101→    try {
102→        const parsed = typeof contentJson === 'string' ? JSON.parse(contentJson) : contentJson;
103→        const texts = [];
104→        let firstImage = null;
105→
106→        const walk = (node) => {
107→            if (!node || typeof node !== 'object') return;
108→
109→            const nodeType = String(node.type || node.__type || '').trim().toLowerCase();
110→            if (nodeType === 'text' && typeof node.text === 'string') {
111→                texts.push(node.text);
112→            }
113→
114→            const isImageNode = nodeType === 'image' || nodeType.endsWith('image') || nodeType.includes('image');
115→            if (!firstImage && isImageNode) {
116→                const image = imageFromNodeLike(node);
117→                if (image) {
118→                    firstImage = image;
119→                }
120→            }
121→
122→            if (Array.isArray(node.children)) {
123→                node.children.forEach(walk);
124→            }
125→        };
126→
127→        if (parsed?.root) {
128→            walk(parsed.root);
129→        }
130→
131→        return {
132→            text: normalizeWhitespace(texts.join(' ')),
133→            image: firstImage
134→        };
135→    } catch {
136→        return { text: '', image: null };
137→    }
138→};
139→
140→const extractFromCanvasDoc = (canvasDocRaw) => {
141→    try {
142→        const doc = typeof canvasDocRaw === 'string' ? JSON.parse(canvasDocRaw) : canvasDocRaw;
143→        const text = Array.isArray(doc?.snippets)
144→            ? normalizeWhitespace(
145→                doc.snippets
146→                    .map((snippet) => (typeof snippet?.text === 'string' ? snippet.text : ''))
147→                    .join(' ')
148→            )
149→            : '';
150→
151→        let image = null;
152→        if (Array.isArray(doc?.images)) {
153→            const first = doc.images.find((img) => imageFromNodeLike(img));
154→            if (first) image = imageFromNodeLike(first);
155→        }
156→
157→        return { text, image };
158→    } catch {
159→        return { text: '', image: null };
160→    }
161→};
162→
163→const buildShareMetaFromJournal = (journal) => {
164→    const lexicalData = extractFromLexical(journal?.content);
165→    const canvasData = extractFromCanvasDoc(journal?.canvas_doc);
166→    const normalizedTitle = typeof journal?.title === 'string' ? normalizeWhitespace(journal.title) : '';
167→    const title = normalizedTitle || 'Untitled Post';
168→    const authorName = normalizeWhitespace(journal?.users?.name) || 'Someone';
169→
170→    let description = lexicalData.text || '';
171→    if (!description && canvasData.text) {
172→        description = canvasData.text;
173→    }
174→    if (!description) {
175→        description = `Read "${title}" by ${authorName} on Iskryb`;
176→    }
177→
178→    let imageCandidate = DEFAULT_OG_IMAGE_URL;
179→    let imageCandidateSource = 'fallback';
180→    if (lexicalData.image?.src) {
181→        imageCandidate = lexicalData.image.src;
182→        imageCandidateSource = 'lexical';
183→    } else if (canvasData.image?.src) {
184→        imageCandidate = canvasData.image.src;
185→        imageCandidateSource = 'canvas';
186→    } else if (journal?.users?.image_url) {
187→        imageCandidate = journal.users.image_url;
188→        imageCandidateSource = 'author_avatar';
189→    }
190→
191→    return {
192→        title,
193→        normalizedTitle,
194→        description: toPreviewText(description),
195→        imageCandidate,
196→        imageCandidateSource
197→    };
198→};
199→
200→const resolveAbsoluteHttpUrl = (rawUrl) => {
201→    try {
202→        const raw = String(rawUrl || '').trim();
203→        if (!raw) return null;
204→
205→        const isSupabasePath =
206→            raw.startsWith('/storage/v1/object/public/')
207→            || raw.startsWith('storage/v1/object/public/');
208→
209→        const baseUrl = isSupabasePath && SUPABASE_URL
210→            ? `${SUPABASE_URL}/`
211→            : SITE_URL;
212→
213→        const parsed = new URL(raw, baseUrl);
214→        if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
215→            return null;
216→        }
217→        return parsed.toString();
218→    } catch {
219→        return null;
220→    }
221→};
222→
223→const isPrivateIpv4Address = (ip) => {
224→    const parts = ip.split('.').map((part) => Number(part));
225→    if (parts.length !== 4 || parts.some((part) => !Number.isInteger(part) || part < 0 || part > 255)) {
226→        return true;
227→    }
228→
229→    const [a, b] = parts;
230→    if (a === 10 || a === 127 || a === 0) return true;
231→    if (a === 169 && b === 254) return true;
232→    if (a === 172 && b >= 16 && b <= 31) return true;
233→    if (a === 192 && b === 168) return true;
234→    return false;
235→};
236→
237→const isPrivateIpv6Address = (ip) => {
238→    const normalized = ip.toLowerCase();
239→    return (
240→        normalized === '::1' ||
241→        normalized.startsWith('fc') ||
242→        normalized.startsWith('fd') ||
243→        normalized.startsWith('fe80:')
244→    );
245→};
246→
247→const isPrivateIpAddress = (ip) => {
248→    const ipVersion = net.isIP(ip);
249→    if (ipVersion === 4) return isPrivateIpv4Address(ip);
250→    if (ipVersion === 6) return isPrivateIpv6Address(ip);
251→    return true;
252→};
253→
254→const isSafeRemoteImageUrl = (imageUrl) => {
255→    try {
256→        const parsed = new URL(imageUrl);
257→        if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
258→            return false;
259→        }
260→
261→        const hostname = parsed.hostname.toLowerCase();
262→        if (!hostname || hostname === 'localhost' || hostname.endsWith('.local') || hostname.endsWith('.internal')) {
263→            return false;
264→        }
265→
266→        if (net.isIP(hostname) && isPrivateIpAddress(hostname)) {
267→            return false;
268→        }
269→
270→        return true;
271→    } catch {
272→        return false;
273→    }
274→};
275→
276→const evaluateShareImageCandidate = (rawUrl) => {
277→    const absoluteUrl = resolveAbsoluteHttpUrl(rawUrl);
278→    if (!absoluteUrl) {
279→        return {
280→            ok: false,
281→            reason: 'invalid_or_non_http_url',
282→            resolvedUrl: null,
283→        };
284→    }
285→
286→    let path = '';
287→    try {
288→        const parsed = new URL(absoluteUrl);
289→        path = String(parsed.pathname || '').toLowerCase();
290→    } catch {
291→        return {
292→            ok: false,
293→            reason: 'invalid_resolved_url',
294→            resolvedUrl: null,
295→        };
296→    }
297→
298→    if (path.endsWith('.svg')) {
299→        return {
300→            ok: false,
301→            reason: 'svg_not_supported_for_share_image',
302→            resolvedUrl: absoluteUrl,
303→        };
304→    }
305→
306→    if (!isSafeRemoteImageUrl(absoluteUrl)) {
307→        return {
308→            ok: false,
309→            reason: 'unsafe_remote_url',
310→            resolvedUrl: absoluteUrl,
311→        };
312→    }
313→
314→    return {
315→        ok: true,
316→        reason: 'ok',
317→        resolvedUrl: absoluteUrl,
318→    };
319→};
320→
321→const fetchRemoteImageBuffer = async (imageUrl) => {
322→    const controller = new AbortController();
323→    const timeout = setTimeout(() => controller.abort(), REMOTE_IMAGE_FETCH_TIMEOUT_MS);
324→
325→    try {
326→        const response = await fetch(imageUrl, {
327→            method: 'GET',
328→            redirect: 'follow',
329→            signal: controller.signal,
330→            headers: {
331→                Accept: 'image/*,*/*;q=0.8',
332→                'Accept-Encoding': 'identity',
333→                'User-Agent': SHARE_IMAGE_FETCH_USER_AGENT,
334→            },
335→        });
336→
337→        if (!response.ok) {
338→            throw new Error(`upstream image status ${response.status}`);
339→        }
340→
341→        const finalUrl = response.url || imageUrl;
342→        if (!isSafeRemoteImageUrl(finalUrl)) {
343→            throw new Error('upstream redirected to unsafe url');
344→        }
345→
346→        const contentType = String(response.headers.get('content-type') || '').toLowerCase();
347→        if (!contentType.startsWith('image/')) {
348→            throw new Error(`upstream content-type ${contentType || 'unknown'} is not an image`);
349→        }
350→        if (contentType.includes('image/svg')) {
351→            throw new Error('svg images are not used for share previews');
352→        }
353→
354→        const headerContentLength = Number(response.headers.get('content-length'));
355→        if (Number.isFinite(headerContentLength) && headerContentLength > REMOTE_IMAGE_MAX_BYTES) {
356→            throw new Error(`upstream content-length exceeds ${REMOTE_IMAGE_MAX_BYTES} bytes`);
357→        }
358→
359→        const arrayBuffer = await response.arrayBuffer();
360→        const buffer = Buffer.from(arrayBuffer);
361→
362→        if (!buffer.length) {
363→            throw new Error('upstream image is empty');
364→        }
365→        if (buffer.length > REMOTE_IMAGE_MAX_BYTES) {
366→            throw new Error(`upstream image exceeds ${REMOTE_IMAGE_MAX_BYTES} bytes`);
367→        }
368→
369→        return {
370→            buffer,
371→            contentType,
372→            byteLength: buffer.length,
373→            finalUrl,
374→        };
375→    } finally {
376→        clearTimeout(timeout);
377→    }
378→};
379→
380→const convertToOgJpeg = async (inputBuffer) => {
381→    return sharp(inputBuffer, { limitInputPixels: 60_000_000 })
382→        .rotate()
383→        .resize(DEFAULT_OG_IMAGE_WIDTH, DEFAULT_OG_IMAGE_HEIGHT, {
384→            fit: 'contain',
385→            background: { r: 255, g: 255, b: 255, alpha: 1 },
386→        })
387→        .jpeg({ quality: 82, mozjpeg: true })
388→        .toBuffer();
389→};
390→
391→const getShareJournal = async (journalId) => {
392→    const { data: journal, error } = await supabase
393→        .from('journals')
394→        .select('id, title, content, post_type, canvas_doc, created_at, users(name, image_url)')
395→        .eq('id', journalId)
396→        .single();
397→
398→    if (error || !journal) {
399→        return null;
400→    }
401→
402→    return journal;
403→};
404→
405→const isShareImageDebugRequest = (req) => {
406→    const debugFlag = String(req?.query?.debug || '').trim().toLowerCase();
407→    return SHARE_IMAGE_DEBUG && (debugFlag === '1' || debugFlag === 'true');
408→};
409→
410→const sendShareImageDebug = (res, payload) => {
411→    return res.status(200).json(payload);
412→};
413→
414→const corsOptions = {
415→    origin: ['https://iskrib.com', 'https://iskrib-v3-client-side.onrender.com', 'http://localhost:5173'],
416→    methods: ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS'],
417→    allowedHeaders: ['Content-Type', 'Authorization'],
418→    credentials: true,
419→    maxAge: 60 * 60 * 24
420→};
421→
422→app.use(cors(corsOptions));
423→app.use(compression({ threshold: 1024 }));
424→app.disable("x-powered-by");
425→app.use(
426→    helmet({
427→        contentSecurityPolicy: false,
428→        crossOriginEmbedderPolicy: false,
429→    })
430→);
431→
432→app.use((req, res, next) => {
433→    if (req.method === "GET" && !req.headers.authorization) {
434→        // no-cache: browser must revalidate with server before using cached response.
435→        // This prevents stale data after mutations (likes, comments, replies, etc.)
436→        // while still allowing conditional requests (304 Not Modified) for performance.
437→        // React Query handles client-side caching, so browser cache is unnecessary.
438→        res.set("Cache-Control", "no-cache");
439→    }
440→    next();
441→});
442→
443→app.use(express.json({ limit: "2mb" }));
444→app.use(express.urlencoded({extended: true, limit: "2mb", parameterLimit: 1000}));
445→
446→// ── Share route: serves OG meta tags for social media previews ──
447→app.get('/share/post/:journalId/image', async (req, res) => {
448→    const { journalId } = req.params;
449→    const debugMode = isShareImageDebugRequest(req);
450→    const debugPayload = {
451→        ok: false,
452→        fallback: false,
453→        journalId,
454→        stage: 'start',
455→        reason: '',
456→        meta: {
457→            imageCandidateSource: null,
458→            imageCandidateRaw: null,
459→            imageCandidateResolved: null,
460→            upstreamFinalUrl: null,
461→            upstreamContentType: null,
462→            upstreamBytes: null,
463→            outputBytes: null,
464→        },
465→    };
466→
467→    const fallbackWithReason = (reason) => {
468→        debugPayload.ok = false;
469→        debugPayload.fallback = true;
470→        debugPayload.stage = 'fallback';
471→        debugPayload.reason = reason;
472→        if (debugMode) {
473→            return sendShareImageDebug(res, debugPayload);
474→        }
475→        return res.redirect(302, DEFAULT_OG_IMAGE_URL);
476→    };
477→
478→    try {
479→        const journal = await getShareJournal(journalId);
480→        debugPayload.stage = 'journal_loaded';
481→        if (!journal) {
482→            return fallbackWithReason('journal_not_found');
483→        }
484→
485→        const shareMeta = buildShareMetaFromJournal(journal);
486→        debugPayload.stage = 'candidate_extracted';
487→        debugPayload.meta.imageCandidateSource = shareMeta.imageCandidateSource;
488→        debugPayload.meta.imageCandidateRaw = shareMeta.imageCandidate;
489→
490→        const candidateEvaluation = evaluateShareImageCandidate(shareMeta.imageCandidate);
491→        debugPayload.meta.imageCandidateResolved = candidateEvaluation.resolvedUrl;
492→        if (!candidateEvaluation.ok || !candidateEvaluation.resolvedUrl) {
493→            return fallbackWithReason(candidateEvaluation.reason);
494→        }
495→
496→        const normalizedFallbackUrl = new URL(DEFAULT_OG_IMAGE_URL).toString();
497→        if (candidateEvaluation.resolvedUrl === normalizedFallbackUrl) {
498→            return fallbackWithReason('candidate_is_default_fallback');
499→        }
500→
501→        debugPayload.stage = 'fetching_upstream';
502→        const remoteImage = await fetchRemoteImageBuffer(candidateEvaluation.resolvedUrl);
503→        debugPayload.stage = 'upstream_loaded';
504→        debugPayload.meta.upstreamFinalUrl = remoteImage.finalUrl;
505→        debugPayload.meta.upstreamContentType = remoteImage.contentType;
506→        debugPayload.meta.upstreamBytes = remoteImage.byteLength;
507→
508→        debugPayload.stage = 'converting_image';
509→        const ogImageBuffer = await convertToOgJpeg(remoteImage.buffer);
510→        debugPayload.stage = 'converted_image';
511→        debugPayload.ok = true;
512→        debugPayload.reason = 'ok';
513→        debugPayload.meta.outputBytes = ogImageBuffer.length;
514→
515→        if (debugMode) {
516→            return sendShareImageDebug(res, debugPayload);
517→        }
518→
519→        res.set('Content-Type', 'image/jpeg');
520→        res.set('Cache-Control', 'public, max-age=3600');
521→        return res.send(ogImageBuffer);
522→    } catch (err) {
523→        debugPayload.stage = 'error';
524→        debugPayload.reason = err?.message || 'unknown_error';
525→        console.error('share image route error:', err?.message || err);
526→        return fallbackWithReason(debugPayload.reason);
527→    }
528→});
