530→app.get('/share/post/:journalId', async (req, res) => {
531→    const { journalId } = req.params;
532→    const shareOrigin = getRequestOrigin(req);
533→    const buildRedirectUrl = (title = '') => makePostUrl(journalId, title);
534→
535→    try {
536→        const journal = await getShareJournal(journalId);
537→        if (!journal) {
538→            return res.redirect(302, buildRedirectUrl(''));
539→        }
540→
541→        const shareMeta = buildShareMetaFromJournal(journal);
542→        const clientPostUrl = buildRedirectUrl(shareMeta.normalizedTitle);
543→        const shareImageUrl = new URL(`/share/post/${journalId}/image`, `${shareOrigin}/`).toString();
544→        const fbAppIdTag = META_FB_APP_ID
545→            ? `<meta property="fb:app_id" content="${escHtml(META_FB_APP_ID)}">`
546→            : '';
547→
548→        const html = `<!DOCTYPE html>
549→<html lang="en">
550→<head>
551→<meta charset="utf-8">
552→<title>${escHtml(shareMeta.title)} | Iskryb</title>
553→<meta name="description" content="${escHtml(shareMeta.description)}">
554→${fbAppIdTag}
555→<link rel="canonical" href="${escHtml(clientPostUrl)}">
556→<meta property="og:type" content="article">
557→<meta property="og:title" content="${escHtml(shareMeta.title)}">
558→<meta property="og:description" content="${escHtml(shareMeta.description)}">
559→<meta property="og:image" content="${escHtml(shareImageUrl)}">
560→<meta property="og:image:width" content="${String(DEFAULT_OG_IMAGE_WIDTH)}">
561→<meta property="og:image:height" content="${String(DEFAULT_OG_IMAGE_HEIGHT)}">
562→<meta property="og:url" content="${escHtml(clientPostUrl)}">
563→<meta property="og:site_name" content="Iskryb">
564→<meta name="twitter:card" content="summary_large_image">
565→<meta name="twitter:title" content="${escHtml(shareMeta.title)}">
566→<meta name="twitter:description" content="${escHtml(shareMeta.description)}">
567→<meta name="twitter:image" content="${escHtml(shareImageUrl)}">
568→<meta name="twitter:image:width" content="${String(DEFAULT_OG_IMAGE_WIDTH)}">
569→<meta name="twitter:image:height" content="${String(DEFAULT_OG_IMAGE_HEIGHT)}">
570→<script>
571→window.location.replace(${JSON.stringify(clientPostUrl)});
572→</script>
573→</head>
574→<body>
575→<p>${escHtml(shareMeta.title)} - Redirecting to Iskryb...</p>
576→<a href="${escHtml(clientPostUrl)}">Click here if not redirected</a>
577→</body>
578→</html>`;
579→
580→        res.set('Content-Type', 'text/html; charset=utf-8');
581→        return res.send(html);
582→    } catch (err) {
583→        console.error('share route error:', err?.message || err);
584→        return res.redirect(302, buildRedirectUrl(''));
585→    }
586→});
587→
588→// Also handle /api/share/post/:journalId so getShareUrl works in both configurations
589→app.get('/api/share/post/:journalId/image', (req, res) => {
590→    res.redirect(301, `/share/post/${req.params.journalId}/image`);
591→});
592→
593→app.get('/api/share/post/:journalId', (req, res) => {
