596→
597→app.use('/api', sitemapRouter);
598→app.use('/api', router);
599→// Keep legacy root routes available while clients migrate to /api.
600→app.use(router)
601→
602→app.get('/', (req, res) => {
603→    res.send(`hello from backend port ${PORT}`)
604→})
605→
606→app.use((req, res) => {
607→    res.status(404).json({ error: "not found" });
608→});
609→
610→app.use((err, _req, res, _next) => {
611→    console.error("unhandled server error:", err?.message || err);
612→    res.status(500).json({ error: "internal server error" });
613→});
